    def _smart_complete(self, ctx: Context, incomplete: str) -> list[CompletionItem]:
        """Look up a completion function for this option based on its
        name and return its results. Used by :meth:`shell_complete` when
        the option was declared with ``auto_complete=True``.

        :param ctx: Invocation context for this command.
        :param incomplete: Value being completed. May be empty.
        """
        complete_func = types.SMART_COMPLETION_PATTERNS.get((self.name or "").lower())

        if complete_func is None:
            return []

        return complete_func(incomplete)

    def shell_complete(self, ctx: Context, incomplete: str) -> list[CompletionItem]:
        """Return a list of completions for the incomplete value. A
        manually provided ``shell_complete`` function always takes
        precedence. Otherwise, if ``auto_complete`` is enabled, smart
        completions are attempted based on the option's name. Falls back
        to the param's type completion.

        :param ctx: Invocation context for this command.
        :param incomplete: Value being completed. May be empty.
        """
        if self._custom_shell_complete is None and self.auto_complete:
            results = self._smart_complete(ctx, incomplete)

            if results:
                return results

        return super().shell_complete(ctx, incomplete)

